import{_ as e,c as a,o as l,a1 as i}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"命令参考：斜杠命令速查表 | Superpowers 教程","description":"学习 Superpowers 斜杠命令。本参考详解 /brainstorm、/write-plan、/execute-plan 命令的触发条件、使用场景、执行步骤和最佳实践，帮助你快速调用核心工作流，遵循 TDD 原则和系统化调试，提高代码质量和开发效率，减少调试时间和错误率，加快迭代速度和交付频率。","frontmatter":{"title":"命令参考：斜杠命令速查表 | Superpowers 教程","sidebarTitle":"命令速查表","subtitle":"命令参考：斜杠命令速查表","description":"学习 Superpowers 斜杠命令。本参考详解 /brainstorm、/write-plan、/execute-plan 命令的触发条件、使用场景、执行步骤和最佳实践，帮助你快速调用核心工作流，遵循 TDD 原则和系统化调试，提高代码质量和开发效率，减少调试时间和错误率，加快迭代速度和交付频率。","tags":["命令","参考","斜杠命令"],"prerequisite":[],"order":270},"headers":[],"relativePath":"zh/obra/superpowers/appendix/commands-reference/index.md","filePath":"zh/obra/superpowers/appendix/commands-reference/index.md"}'),r={name:"zh/obra/superpowers/appendix/commands-reference/index.md"};function o(s,t,n,d,p,h){return l(),a("div",null,[...t[0]||(t[0]=[i('<h1 id="命令参考-斜杠命令速查表" tabindex="-1">命令参考：斜杠命令速查表 <a class="header-anchor" href="#命令参考-斜杠命令速查表" aria-label="Permalink to &quot;命令参考：斜杠命令速查表&quot;">​</a></h1><p>Superpowers 提供了三个斜杠命令，用于快速调用核心工作流技能。</p><h2 id="命令一览" tabindex="-1">命令一览 <a class="header-anchor" href="#命令一览" aria-label="Permalink to &quot;命令一览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>命令</th><th>描述</th><th>调用技能</th><th>适用场景</th></tr></thead><tbody><tr><td><code>/brainstorm</code></td><td>创意设计需求澄清</td><td>brainstorming</td><td>创造性工作前</td></tr><tr><td><code>/write-plan</code></td><td>编写详细实施计划</td><td>writing-plans</td><td>有规格/需求的多步任务前</td></tr><tr><td><code>/execute-plan</code></td><td>批量执行计划任务</td><td>executing-plans</td><td>执行已有计划时</td></tr></tbody></table><hr><h2 id="brainstorm" tabindex="-1">/brainstorm <a class="header-anchor" href="#brainstorm" aria-label="Permalink to &quot;/brainstorm&quot;">​</a></h2><p><strong>描述</strong>：在设计前进行需求澄清和创意探索</p><p><strong>触发条件</strong>：</p><ul><li>创建新功能</li><li>构建新组件</li><li>添加新功能</li><li>修改现有行为</li></ul><p><strong>调用技能</strong>：<code>superpowers:brainstorming</code></p><p><strong>使用示例</strong>：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/brainstorm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;为用户添加个人资料编辑功能&quot;</span></span></code></pre></div><p><strong>核心流程</strong>：</p><ol><li>理解项目上下文</li><li>逐个提出澄清问题（一次一个）</li><li>展示设计方案（200-300 字分段）</li><li>保存设计文档到 <code>docs/plans/</code></li><li>提交设计到版本控制</li></ol><p><strong>注意事项</strong>：</p><ul><li>必须在写代码前执行</li><li>每次只提一个问题</li><li>设计文档必须提交</li></ul><hr><h2 id="write-plan" tabindex="-1">/write-plan <a class="header-anchor" href="#write-plan" aria-label="Permalink to &quot;/write-plan&quot;">​</a></h2><p><strong>描述</strong>：将需求分解为可执行的小任务</p><p><strong>触发条件</strong>：</p><ul><li>已有清晰的需求或规格</li><li>需要多步实施的任务</li><li>需要详细实施计划</li></ul><p><strong>调用技能</strong>：<code>superpowers:writing-plans</code></p><p><strong>使用示例</strong>：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/write-plan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;docs/plans/2024-02-01-user-profile-design.md&quot;</span></span></code></pre></div><p><strong>核心流程</strong>：</p><ol><li>阅读设计文档或需求规格</li><li>分解为 2-5 分钟可完成的任务</li><li>为每个任务编写完整代码</li><li>包含测试步骤</li><li>保存实施计划</li></ol><p><strong>任务分解原则</strong>：</p><ul><li>每个任务可在 2-5 分钟内完成</li><li>任务粒度小到&quot;无需上下文&quot;的工程师也能执行</li><li>每个任务包含实现和验证</li></ul><p><strong>注意事项</strong>：</p><ul><li>任务必须足够小</li><li>每个任务必须有验收标准</li><li>计划文档应清晰易读</li></ul><hr><h2 id="execute-plan" tabindex="-1">/execute-plan <a class="header-anchor" href="#execute-plan" aria-label="Permalink to &quot;/execute-plan&quot;">​</a></h2><p><strong>描述</strong>：批量执行计划中的任务，包含审查检查点</p><p><strong>触发条件</strong>：</p><ul><li>已有编写好的实施计划</li><li>需要批量执行任务</li><li>在独立会话中执行（推荐）</li></ul><p><strong>调用技能</strong>：<code>superpowers:executing-plans</code></p><p><strong>使用示例</strong>：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/execute-plan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;docs/plans/2024-02-01-user-profile-implementation.md&quot;</span></span></code></pre></div><p><strong>核心流程</strong>：</p><ol><li>读取实施计划</li><li>逐个执行任务</li><li>每个任务后运行测试</li><li>每批任务后设置审查检查点</li><li>完成所有任务后验证</li></ol><p><strong>执行策略</strong>：</p><ul><li>按顺序执行任务</li><li>每个任务后验证测试</li><li>每批任务（通常 3-5 个）后进行代码审查</li><li>失败时停止并调试</li></ul><p><strong>注意事项</strong>：</p><ul><li>适用于独立会话执行</li><li>与 subagent-driven-development 的区别在于执行方式</li><li>必须遵守 TDD 原则</li></ul><hr><h2 id="命令使用建议" tabindex="-1">命令使用建议 <a class="header-anchor" href="#命令使用建议" aria-label="Permalink to &quot;命令使用建议&quot;">​</a></h2><h3 id="何时使用命令" tabindex="-1">何时使用命令 <a class="header-anchor" href="#何时使用命令" aria-label="Permalink to &quot;何时使用命令&quot;">​</a></h3><p><strong>使用命令时</strong>：</p><ul><li>你清楚知道需要哪个工作流</li><li>想快速启动标准流程</li><li>在 Claude Code 中使用</li></ul><p><strong>直接使用技能时</strong>：</p><ul><li>不确定需要哪个技能</li><li>AI 主动建议使用技能</li><li>通过 Skill tool 调用</li></ul><h3 id="命令-vs-技能" tabindex="-1">命令 vs 技能 <a class="header-anchor" href="#命令-vs-技能" aria-label="Permalink to &quot;命令 vs 技能&quot;">​</a></h3><table tabindex="0"><thead><tr><th>方面</th><th>斜杠命令</th><th>技能调用</th></tr></thead><tbody><tr><td>调用方式</td><td>用户主动输入 <code>/command</code></td><td>AI 自动调用或通过 Skill tool</td></tr><tr><td>适用场景</td><td>明确知道需要哪个流程</td><td>让 AI 推荐合适流程</td></tr><tr><td>平台支持</td><td>Claude Code</td><td>Claude Code、OpenCode、Codex</td></tr></tbody></table><h3 id="典型工作流" tabindex="-1">典型工作流 <a class="header-anchor" href="#典型工作流" aria-label="Permalink to &quot;典型工作流&quot;">​</a></h3><p><strong>完整开发流程</strong>：</p><ol><li><code>/brainstorm</code> - 设计需求</li><li><code>/write-plan</code> - 编写计划</li><li><code>/execute-plan</code> - 执行实施</li></ol><p><strong>修复 Bug 流程</strong>：</p><ul><li>直接使用 <code>systematic-debugging</code> 技能</li></ul><p><strong>快速原型流程</strong>：</p><ul><li><code>/brainstorm</code> - 快速设计</li><li>直接实现（跳过详细计划）</li></ul><hr><h2 id="本课小结" tabindex="-1">本课小结 <a class="header-anchor" href="#本课小结" aria-label="Permalink to &quot;本课小结&quot;">​</a></h2><p>本课介绍了 Superpowers 提供的三个斜杠命令：</p><ul><li><code>/brainstorm</code>：创意设计需求澄清</li><li><code>/write-plan</code>：编写详细实施计划</li><li><code>/execute-plan</code>：批量执行计划任务</li></ul><p>这些命令在 Claude Code 中提供快速访问核心工作流的便捷方式，适用于你知道需要哪个流程的场景。</p><h2 id="下一课预告" tabindex="-1">下一课预告 <a class="header-anchor" href="#下一课预告" aria-label="Permalink to &quot;下一课预告&quot;">​</a></h2><blockquote><p>下一课我们学习 <strong><a href="./../agents-reference/">代理参考</a></strong>。</p><p>你会学到：</p><ul><li>代理系统的概念和用途</li><li>code-reviewer 代理的详细说明</li><li>如何定义和使用自定义代理</li></ul></blockquote><hr><h2 id="附录-源码参考" tabindex="-1">附录：源码参考 <a class="header-anchor" href="#附录-源码参考" aria-label="Permalink to &quot;附录：源码参考&quot;">​</a></h2><details><summary><strong>点击展开查看源码位置</strong></summary><blockquote><p>更新时间：2026-02-01</p></blockquote><table tabindex="0"><thead><tr><th>命令</th><th>文件路径</th><th>行号</th></tr></thead><tbody><tr><td>/brainstorm 命令定义</td><td><a href="https://github.com/obra/superpowers/blob/main/commands/brainstorm.md" target="_blank" rel="noreferrer"><code>commands/brainstorm.md</code></a></td><td>1-7</td></tr><tr><td>/write-plan 命令定义</td><td><a href="https://github.com/obra/superpowers/blob/main/commands/write-plan.md" target="_blank" rel="noreferrer"><code>commands/write-plan.md</code></a></td><td>1-7</td></tr><tr><td>/execute-plan 命令定义</td><td><a href="https://github.com/obra/superpowers/blob/main/commands/execute-plan.md" target="_blank" rel="noreferrer"><code>commands/execute-plan.md</code></a></td><td>1-7</td></tr></tbody></table><p><strong>关键特性</strong>：</p><ul><li><code>disable-model-invocation: true</code>：禁止模型直接调用，确保通过技能系统执行</li><li>命令文件仅包含指令调用，实际逻辑在对应技能中</li></ul><p><strong>调用链路</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>斜杠命令 → 技能系统 (Skill tool) → 对应技能 (SKILL.md) → 执行工作流</span></span></code></pre></div></details>',70)])])}const g=e(r,[["render",o]]);export{u as __pageData,g as default};
